// Funzione Salva richiesta
window.saveTheme = function() {
    const finalColor = window.updateCustomPicker();
    localStorage.setItem("userPrimaryColor", finalColor);
    window.updateTheme();
    window.chiudiPopupSettings();
};

// Funzione di aggiornamento tema (da chiamare anche al caricamento app)
window.updateTheme = function() {
    const root = document.documentElement;
    const isAdmin = localStorage.getItem("isAdmin") === "true";
    const userColor = localStorage.getItem("userPrimaryColor");

    if (isAdmin) {
        // Se Admin, vince il giallo (definito in style-variables.css o fallback)
        const adminColor = getComputedStyle(root).getPropertyValue('--admin-color').trim() || "#ffcc00";
        root.style.setProperty('--primary', adminColor);
    } else if (userColor) {
        // Se c'è un colore scelto dall'utente
        root.style.setProperty('--primary', userColor);
    } else {
        // Default assoluto (Verde Polismile)
        root.style.setProperty('--primary', '#27ae60');
    }
};

window.resetTheme = function() {
    const defaultColor = '#27ae60';
    updateSliders(defaultColor);
};

async function initApp() {
    try {
        // Prima di tutto carichiamo il tema salvato
        window.updateTheme();

        await window.registerUserId();
        //window.updateThemeBasedOnAdmin();

        const logo = document.getElementById("logo-admin");
        if (logo) {
            let lastTap = 0;
            logo.addEventListener('click', function () {
                const now = new Date().getTime();
                if (now - lastTap < 300 && now - lastTap > 0) Login();
                lastTap = now;
            });
        }
        checkLiveStatus(); 
        verificaNovitaAllenamenti();
        verificaNovitaFIP();
        setInterval(checkLiveStatus, 10000);
    } catch (error) { console.error(error); }
}

document.addEventListener("DOMContentLoaded", initApp);
window.onclick = (e) => { if (e.target == document.getElementById('customPopup')) chiudiPopup(); }
